import React from 'react';
import { AsyncStorage } from 'react-native';

const logger = {
  networkRequests: [],
  asyncStorageOperations: [],
  userActions: [],
  stateChanges: []
};

function logNetworkRequest(method, url, data) {
  const request = { method, url, data };
  logger.networkRequests.push(request);
  console.log('Network Request:', request);
}

async function logAsyncStorageOperation(action, key, value) {
  const operation = { action, key, value };
  logger.asyncStorageOperations.push(operation);
  try {
    if (action === 'set') {
      await AsyncStorage.setItem(key, JSON.stringify(value));
    } else if (action === 'get') {
      const data = await AsyncStorage.getItem(key);
      console.log('AsyncStorage Get:', { key, value: JSON.parse(data) });
    }
  } catch (error) {
    console.error('AsyncStorage Error:', error);
  }
}

function logUserAction(action, details) {
  const userAction = { action, details };
  logger.userActions.push(userAction);
  console.log('User Action:', userAction);
}

function logStateChange(stateName, newState) {
  const stateChange = { stateName, newState };
  logger.stateChanges.push(stateChange);
  console.debug('State Change:', stateChange);
}

export {
  logNetworkRequest,
  logAsyncStorageOperation,
  logUserAction,
  logStateChange
};